    }

    fn set_field(&mut self, idx: i32, k: &[u8]) -> Result<(), LuaError> {
        lua_vm::api::set_field(self, idx, k)
    }

    fn set_global(&mut self, name: &[u8]) -> Result<(), LuaError> {
