1315	/// Copy populated fields from the canonical `lua_vm::debug::LuaDebug` into
1316	/// the Phase-B stub `LuaDebug`. The two structs diverge on a few field types
1317	/// (e.g. `what` is a single byte tag in the stub vs. `Option<&'static [u8]>`
1318	/// in the canonical struct, `short_src` is `Vec<u8>` vs. fixed array).
1319	/// Copy only the fields that `lua_getinfo`'s `what` string actually populates
1320	/// in C. Mirrors `auxgetinfo` in `ldebug.c`: each option byte writes a disjoint
1321	/// subset of `lua_Debug`. Calling `get_info` with one option string must not
1322	/// clobber fields populated by an earlier call with a different option string
1323	/// (a pattern the auxiliary library relies on — `pushglobalfuncname` calls
1324	/// `lua_getinfo(L, "f", ar)` and expects the previously-set `namewhat`/`what`/
1325	/// `short_src`/`linedefined` to survive).
1326	fn copy_lvm_debug_to_stub_selective(
1327	    src: &lua_vm::debug::LuaDebug,
1328	    dst: &mut LuaDebug,
1329	    what: &[u8],
1330	) {
1331	    dst.i_ci_idx = src.i_ci;
1332	    for &ch in what {
1333	        match ch {
1334	            b'S' => {
1335	                dst.what = match src.what {
1336	                    Some(b"Lua") => b'L',
1337	                    Some(b"C") => b'C',
1338	                    Some(b"main") => b'm',
1339	                    _ => 0,
1340	                };
1341	                dst.source = src.source.clone().unwrap_or_default();
1342	                let zero = src
1343	                    .short_src
1344	                    .iter()
1345	                    .position(|&b| b == 0)
1346	                    .unwrap_or(src.short_src.len());
1347	                dst.short_src = src.short_src[..zero].to_vec();
1348	                dst.linedefined = src.linedefined;
1349	                dst.lastlinedefined = src.lastlinedefined;
1350	            }
1351	            b'l' => {
1352	                dst.currentline = src.currentline;
1353	            }
1354	            b'u' => {
1355	                dst.nups = src.nups;
1356	                dst.nparams = src.nparams;
1357	                dst.isvararg = src.isvararg;
1358	            }
1359	            b't' => {
1360	                dst.istailcall = src.istailcall;
1361	            }
1362	            b'n' => {
1363	                dst.name = src.name.clone();
1364	                dst.namewhat = src.namewhat.map(|s| s.to_vec()).unwrap_or_default();
1365	            }
1366	            b'r' => {
1367	                dst.ftransfer = src.ftransfer;
1368	                dst.ntransfer = src.ntransfer;
1369	            }
1370	            _ => {}
1371	        }
1372	    }
1373	}
