1377	struct StubBStr<'a>(&'a [u8]);
1378	
1379	impl<'a> std::fmt::Display for StubBStr<'a> {
1380	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
1381	        use std::fmt::Write as _;
1382	        for &b in self.0 {
1383	            if b.is_ascii() {
1384	                f.write_char(b as char)?;
1385	            } else {
1386	                write!(f, "\\x{:02x}", b)?;
1387	            }
1388	        }
1389	        Ok(())
1390	    }
1391	}
