///
/// C: `LUA_API void lua_sethook(lua_State *L, lua_Hook func, int mask, int count)`
pub fn set_hook(
    state: &mut LuaState,
    func: Option<Box<dyn FnMut(&mut LuaState, &LuaDebug)>>,
    mask: i32,
    count: i32,
) {
    // C: if (func == NULL || mask == 0) { mask = 0; func = NULL; }
    let (func, mask) = if func.is_none() || mask == 0 {
        (None, 0i32)
    } else {
        (func, mask)
