        if self.push_where(level).is_err() {
            return LuaError::runtime(format_args!("{}", StubBStr(msg)));
        }
        let mut full = self.pop_bytes();
        full.extend_from_slice(msg);
        LuaError::runtime(format_args!("{}", StubBStr(&full)))
    }

